exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <string>

class Shape
{
public:
    virtual double area() const = 0;
    virtual ~Shape() = default;
};

class Circle : public Shape
{
    double m_radius{};
public:
    Circle(double radius) : m_radius{radius} {}
    double area() const override { return 3.14159265 * m_radius * m_radius; }
};

class Rectangle : public Shape
{
    double m_width{};
    double m_height{};
public:
    Rectangle(double w, double h) : m_width{w}, m_height{h} {}
    double area() const override { return m_width * m_height; }
};

int main()
{
    std::string type{};
    std::cin >> type;

    Shape* shape{nullptr};

    if (type == "circle")
    {
        double r{};
        std::cin >> r;
        shape = new Circle{r};
    }
    else
    {
        double w{}, h{};
        std::cin >> w >> h;
        shape = new Rectangle{w, h};
    }

    std::cout << "Area: " << std::fixed << std::setprecision(2) << shape->area() << '\n';
    delete shape;

    return 0;
}

