exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <sstream>
#include <string>

class IPrintable
{
public:
    virtual std::string getDescription() const = 0;
    virtual ~IPrintable() = default;
};

class Book : public IPrintable
{
    std::string m_title{};
public:
    Book(const std::string& title) : m_title{title} {}
    std::string getDescription() const override { return "Book: " + m_title; }
};

class Invoice : public IPrintable
{
    double m_amount{};
public:
    Invoice(double amount) : m_amount{amount} {}
    std::string getDescription() const override
    {
        std::ostringstream oss{};
        oss << "Invoice: $" << std::fixed << std::setprecision(2) << m_amount;
        return oss.str();
    }
};

int main()
{
    int n{};
    std::cin >> n;
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        IPrintable* obj{nullptr};
        if (type == "book")
        {
            std::string title{};
            std::cin >> title;
            obj = new Book{title};
        }
        else
        {
            double amount{};
            std::cin >> amount;
            obj = new Invoice{amount};
        }
        std::cout << obj->getDescription() << '\n';
        delete obj;
    }
    return 0;
}
